  ('public-health-specialist-moex-01057', 'public-health-specialist', 'public-health-specialist-moex-110-6b8439ac', 'sub-public-health-specialist-06', NULL, 'single_choice', '根據衛生福利部中央健康保險署三代倉儲系統資料分析統計顯示，2020年全民健康保險醫療費用 最多之疾病為何？', '["高血壓", "急性腎衰竭及慢性腎臟疾病性疾病", "口腔及唾液腺之疾病", "腦血管疾病"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "3a750b585031", "answer_pdf_sha1": "b6cfac31f8cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政與管理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
